// ================================================================
// WF-2 · CONVERSATION CAPTURE v2.1
// 1 security · 2 analyze thread · 3 find contact · 4 log history
// 5 update rollups · 6 callout learning · 7 DRAFT A REPLY in
// Sagnik's voice (style guide §4.6/§11/§6) · 8 respond
// ================================================================

const helpers = this.helpers;
const payload = $json.body || {};

// ---------- 1. SECURITY ----------
if (payload.secret !== $env.LINKUP_SECRET) {
  throw new Error('Unauthorized — wrong or missing secret');
}

const threadText = String(payload.page_text || '').slice(-9000);
if (!threadText) throw new Error('Empty conversation text');

// ---------- Helpers ----------
async function askClaude(model, maxTokens, prompt, systemPrompt) {
  let res;
  try {
    res = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model, max_tokens: maxTokens,
        system: systemPrompt || undefined,   // no temperature: sonnet-5 thinks by default
        messages: [{ role: 'user', content: prompt }],
      }),
    });
  } catch (e) {
    const detail = JSON.stringify(
      (e.response && (e.response.data || e.response.body)) ||
      (e.cause && e.cause.response && e.cause.response.data) ||
      e.description || e.message
    );
    throw new Error('CLAUDE call failed (model ' + model + '): ' + detail);
  }
  if (typeof res === 'string') res = JSON.parse(res);
  const textBlock = (res.content || []).find((b) => b.type === 'text');
  if (!textBlock || !textBlock.text) {
    throw new Error('Unexpected Claude reply: ' + JSON.stringify(res).slice(0, 400));
  }
  return textBlock.text;
}

function extractJson(text) {
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Claude did not return JSON. Got: ' + text.slice(0, 200));
  return JSON.parse(match[0]);
}

async function supabase(method, path, body, extraHeaders) {
  let res;
  try {
    res = await helpers.httpRequest({
      method,
      url: $env.SUPABASE_URL + path,
      headers: {
        apikey: $env.SUPABASE_SERVICE_KEY,
        Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
        'content-type': 'application/json',
        ...(extraHeaders || {}),
      },
      body: body === undefined ? undefined : JSON.stringify(body),
    });
  } catch (e) {
    const detail = JSON.stringify(
      (e.response && (e.response.data || e.response.body)) ||
      (e.cause && e.cause.response && e.cause.response.data) ||
      e.description || e.message
    );
    throw new Error('SUPABASE call failed (' + method + ' ' + path + '): ' + detail);
  }
  if (typeof res === 'string' && res.trim().length) res = JSON.parse(res);
  return res;
}

// ---------- 2. AI — analyze the conversation ----------
const participantHint = payload.participant
  ? `The other person in this thread is: ${payload.participant}. Use exactly this as contact_name.`
  : 'Identify the OTHER person (not Sagnik) from the messages.';

const prompt = `Analyze this LinkedIn conversation between Sagnik (a job-seeking
BITS Pilani student) and one other person. ${participantHint}

Return ONLY JSON with exactly these keys:
{"contact_name": string,
 "headline": string or null   (their professional tagline if determinable, e.g. "Senior PM at Flipkart"),
 "company": string or null    (their CURRENT company),
 "role": string or null       (their job title / role),
 "previous_companies": string[]  (past employers mentioned; [] if none),
 "college": string or null,
 "location": string or null,
 "is_bits_alum": boolean       (true ONLY if BITS Pilani is their college),
 "first_message": string or null  (the FIRST message Sagnik sent in this thread, verbatim if identifiable),
 "summary": string  (3-4 sentences: where does this relationship stand?),
 "advice": string[],
 "referrals": string[],
 "hiring_timeline": string[],
 "promises": string[],
 "action_items_for_sagnik": string[],
 "sentiment": "warm" or "neutral" or "cold",
 "relationship_strength": 1-5,
 "referral_potential": 1-5,
 "suggested_next_follow_up": "YYYY-MM-DD" or null  (today is ${new Date().toISOString().slice(0,10)}),
 "follow_up_reason": string or null,
 "ai_callout": string or null}

For the profile fields (headline, company, role, previous_companies, college,
location, is_bits_alum, first_message): infer them from the conversation. Use
null (or [] for arrays) when a field is NOT clearly determinable — never invent
a company or title you did not actually see in the text.
ai_callout: if the OTHER person accuses Sagnik of using AI/ChatGPT, quote their
exact sentence; otherwise null.
The text is a raw page capture with UI noise — ignore the noise.

CONVERSATION:
${threadText}`;

const a = extractJson(await askClaude('claude-haiku-4-5-20251001', 1200, prompt));

// Collect only the profile fields the AI could actually determine.
const profileFields = {};
if (a.headline) profileFields.headline = a.headline;
if (a.company) profileFields.company = a.company;
if (a.role) profileFields.role = a.role;
if (Array.isArray(a.previous_companies) && a.previous_companies.length) {
  profileFields.previous_companies = a.previous_companies;
}
if (a.college) profileFields.college = a.college;
if (a.location) profileFields.location = a.location;
if (a.is_bits_alum === true) profileFields.is_bits_alum = true;
if (a.first_message) profileFields.first_message = a.first_message;

// ---------- 3. FIND (or AUTO-CREATE) THE CONTACT ----------
const PROFILE_COLS =
  'id,full_name,headline,company,role,previous_companies,' +
  'college,location,is_bits_alum,first_message';
const name = (payload.participant || a.contact_name || '').trim();
if (!name || /multiple|conversation|contact/i.test(name)) {
  return [{ json: { ok: false,
    error: 'Could not identify who this thread is with. Open a single ' +
           'conversation (not the message list) and capture again.' } }];
}

let found = await supabase(
  'GET',
  '/rest/v1/contacts?select=' + PROFILE_COLS + '&full_name=ilike.*' +
    encodeURIComponent(name) + '*'
);

let autoCreated = false;
if (!found || !found.length) {
  // Messaged before LinkUp existed → create a record now, pre-filled with
  // whatever the AI could infer from the conversation.
  const created = await supabase(
    'POST',
    '/rest/v1/contacts?on_conflict=linkedin_url&select=' + PROFILE_COLS,
    [{
      linkedin_url: String(payload.url || '').split('?')[0],
      full_name: name,
      status: 'in_conversation',
      connection_date: new Date().toISOString().slice(0, 10),
      ai_notes: 'Auto-created from conversation capture. Open their profile and click Capture Profile to enrich this record.',
      ...profileFields,
    }],
    { Prefer: 'resolution=merge-duplicates,return=representation' }
  );
  found = created;
  autoCreated = true;
}
const c = found[0];
const today = new Date().toISOString().slice(0, 10);

// Backfill: for an EXISTING contact, fill only columns that are still empty,
// so a real profile capture's richer data is never overwritten.
if (!autoCreated) {
  const backfill = {};
  for (const [k, v] of Object.entries(profileFields)) {
    const cur = c[k];
    const empty = cur === null || cur === undefined || cur === '' ||
      (Array.isArray(cur) && cur.length === 0) ||
      (k === 'is_bits_alum' && !cur);
    if (empty) backfill[k] = v;
  }
  if (Object.keys(backfill).length) {
    await supabase('PATCH', '/rest/v1/contacts?id=eq.' + c.id, backfill);
    Object.assign(c, backfill);
  }
}

// ---------- 4. APPEND TO HISTORY ----------
await supabase('POST', '/rest/v1/interactions', [{
  contact_id: c.id,
  direction: 'capture',
  raw_text: threadText,
  summary: a.summary,
  sentiment: a.sentiment,
  key_points: {
    advice: a.advice, referrals: a.referrals, hiring: a.hiring_timeline,
    promises: a.promises, action_items: a.action_items_for_sagnik,
  },
}]);

// ---------- 5. UPDATE THE CONTACT'S ROLLUP FIELDS ----------
const patch = {
  conversation_summary: a.summary,
  last_contacted: today,
  relationship_strength: a.relationship_strength,
  referral_potential: a.referral_potential,
  status: 'in_conversation',
  updated_at: new Date().toISOString(),
};
if (a.suggested_next_follow_up) patch.next_follow_up = a.suggested_next_follow_up;
if (a.hiring_timeline && a.hiring_timeline.length) {
  patch.hiring_status = 'hiring_later';
  patch.hiring_notes = a.hiring_timeline.join('; ');
}
await supabase('PATCH', '/rest/v1/contacts?id=eq.' + c.id, patch);

// ---------- 6. AI-CALLOUT LEARNING LOOP ----------
if (a.ai_callout) {
  const lastEx = await supabase('GET',
    '/rest/v1/message_examples?contact_id=eq.' + c.id +
    '&order=captured_at.desc&limit=1&select=id');
  if (lastEx.length) {
    await supabase('PATCH', '/rest/v1/message_examples?id=eq.' + lastEx[0].id, {
      outcome: 'callout_ai', quality_score: 0.05, callout_reason: a.ai_callout,
    });
  }
  const vpc = (await supabase('GET', '/rest/v1/voice_profile?id=eq.1&select=drafts_callouts'))[0];
  await supabase('PATCH', '/rest/v1/voice_profile?id=eq.1', {
    drafts_callouts: (vpc.drafts_callouts || 0) + 1,
    updated_at: new Date().toISOString(),
  });
}

// ---------- 7. DRAFT A REPLY IN SAGNIK'S VOICE ----------
const cfg = await supabase('GET', '/rest/v1/prompt_config?id=eq.1&select=content');
const styleGuide = (cfg && cfg.length) ? cfg[0].content : '';

let reply = null;
let replyExampleId = null;
if (styleGuide) {
  const replyTask = `TASK: Draft Sagnik's REPLY to the latest message from ${a.contact_name},
following the style guide's reply rules (§4.6, §11) exactly. Pick the right
reply template from §6/§11 based on what they said (referral thanks 6H,
portal dead-end 6F, rejection 6I, AI-callout recovery 6K, structured
program 6L, or a plain warm reply).

ANALYSIS OF WHERE THINGS STAND: ${JSON.stringify({
    summary: a.summary, referrals: a.referrals, promises: a.promises,
    hiring: a.hiring_timeline, sentiment: a.sentiment, ai_callout: a.ai_callout,
  })}

THE CONVERSATION (raw capture, latest messages at the END; ignore UI noise):
${threadText}

Reminders: replies are short, formal but human. NO "Sagnik" sign-off on
replies. No over-apologising. No Porter/12-month pitch repetition unless
they asked. Output ONLY the reply message.`;

  reply = (await askClaude('claude-sonnet-5', 1500, replyTask, styleGuide)).trim();

  // Log it so the feedback buttons + learning loop cover replies too
  const ex = await supabase('POST', '/rest/v1/message_examples?select=id', [{
    contact_id: c.id,
    message_type: 'reply',
    classification: { sentiment: a.sentiment, special: a.ai_callout ? 'callout_recovery' : 'none' },
    profile_snippet: (a.summary || '').slice(0, 500),
    input_context: threadText.slice(-2000),
    draft_original: reply,
  }], { Prefer: 'return=representation' });
  replyExampleId = ex[0].id;
}

// ---------- 8. REPLY TO THE EXTENSION ----------
return [{ json: {
  ok: true, auto_created: autoCreated || undefined, captured_fields: profileFields,
  summary: a.summary,
  action_items: a.action_items_for_sagnik,
  next_follow_up: a.suggested_next_follow_up,
  ai_callout_detected: a.ai_callout || undefined,
  reply: reply,
  example_id: replyExampleId,
} }];
